class Solution:
    def validateStackSequences(self, pushed, popped):
        from itertools import permutations
        # only feasible for very small inputs; used as oracle on stress
        stack = []
        j = 0
        for v in pushed:
            stack.append(v)
            while stack and j < len(popped) and stack[-1] == popped[j]:
                stack.pop()
                j += 1
        return len(stack) == 0

